import{_ as a,c as s,S as t,o as n}from"./chunks/framework.CsEN6QFL.js";const u=JSON.parse('{"title":"Event Display","description":"","frontmatter":{},"headers":[],"relativePath":"spaces/event-display.md","filePath":"spaces/event-display.md","lastUpdated":1776165494000}'),o={name:"spaces/event-display.md"};function i(l,e,c,r,d,p){return n(),s("div",null,e[0]||(e[0]=[t(`<h1 id="event-display" tabindex="-1">Event Display <a class="header-anchor" href="#event-display" aria-label="Permalink to &quot;Event Display&quot;">​</a></h1><p><strong>Live:</strong> <a href="https://huggingface.co/spaces/CERN/colliderml-event-display" target="_blank" rel="noreferrer">huggingface.co/spaces/CERN/colliderml-event-display</a><strong>Source:</strong> <a href="https://github.com/OpenDataDetector/ColliderML/tree/main/spaces/event-display" target="_blank" rel="noreferrer"><code>spaces/event-display/</code></a></p><p>Interactive 3D viewer for single events from the ColliderML datasets. Pick a process and an event ID to see the tracker hits, reconstructed tracks, and truth particles inside the OpenDataDetector geometry — rendered with Plotly so you can rotate, zoom, and toggle layers.</p><h2 id="what-you-can-see" tabindex="-1">What you can see <a class="header-anchor" href="#what-you-can-see" aria-label="Permalink to &quot;What you can see&quot;">​</a></h2><ul><li><strong>Blue points</strong> — tracker hits, coloured by detector layer (or <code>volume_id</code> / <code>particle_id</code> if layer is missing).</li><li><strong>Red lines</strong> — reconstructed tracks, approximated as helical polylines from the perigee parameters (<code>d0</code>, <code>z0</code>, <code>phi</code>, <code>theta</code>, <code>qop</code>). This is a visualisation aid, not a physics-accurate reconstruction.</li><li><strong>Yellow dashes</strong> — truth-particle momentum vectors drawn from the primary vertex, restricted to primary particles and capped at the 20 highest-momentum entries so the plot stays readable.</li></ul><h2 id="datasets" tabindex="-1">Datasets <a class="header-anchor" href="#datasets" aria-label="Permalink to &quot;Datasets&quot;">​</a></h2><p>The dropdown ships with a curated subset of the catalogue so the UI stays responsive on the Space&#39;s modest resources:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>ttbar_pu0</span></span>
<span class="line"><span>ttbar_pu200</span></span>
<span class="line"><span>higgs_portal_pu10</span></span>
<span class="line"><span>zmumu_pu0</span></span>
<span class="line"><span>diphoton_pu0</span></span>
<span class="line"><span>single_muon_pu0</span></span></code></pre></div><p>Each selection loads at most 50 events into memory. If you want a different process, open an issue — or run the Space locally and edit <code>DATASETS</code> in <code>app.py</code>.</p><h2 id="data-loading" tabindex="-1">Data loading <a class="header-anchor" href="#data-loading" aria-label="Permalink to &quot;Data loading&quot;">​</a></h2><p>The Space prefers its own on-disk cache (<code>_cached_events/&lt;dataset&gt;/*.parquet</code>) if present; <code>cache_events.py</code> populates it by calling <code>colliderml.load()</code> once for each dataset and writing the results to parquet. On a fresh Space with an empty cache the app falls back to calling <code>colliderml.load()</code> live from the dataset&#39;s HuggingFace repo — slower on first hit, then cached in memory via <code>functools.lru_cache</code>.</p><h2 id="running-it-locally" tabindex="-1">Running it locally <a class="header-anchor" href="#running-it-locally" aria-label="Permalink to &quot;Running it locally&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spaces/event-display</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install -r requirements.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.py</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Open http://localhost:7860</span></span></code></pre></div><h2 id="customisation" tabindex="-1">Customisation <a class="header-anchor" href="#customisation" aria-label="Permalink to &quot;Customisation&quot;">​</a></h2><ul><li>Add a dataset → append to <code>DATASETS</code> in <code>app.py</code> and re-run <code>cache_events.py</code>.</li><li>Add a visualisation layer (e.g. calo cells) → follow the pattern for <code>tracker_hits</code> in <code>render_event()</code> and add a new <code>colliderml.load</code> table to the list in <code>_load_dataset()</code>.</li><li>Change the colour scheme → the Plotly <code>Scatter3d</code> traces carry all the knobs; search for <code>Viridis</code> and <code>crimson</code> in <code>app.py</code>.</li></ul>`,15)]))}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
